<template>
  <nav class="bg-pink-400 shadow-md fixed top-0 w-full z-10">
    <div class="relative flex items-center justify-between h-14">
      <div class="flex-1 flex items-stretch justify-start ml-6">
        <div class="flex-shrink-0 flex items-center">
          <a href="#" class="text-white text-xl">ウマ娘 計算機置き場</a>
        </div>
        <div class="ml-10">
          <div class="flex space-x-5">
            <div
              v-for="item in menu"
              :key="item.value"
              class="flex relative h-14 items-center"
              :class="{
                'menu-item': true,
                'active-item': modelValue == item.value,
                'text-white': modelValue == item.value,
                'text-gray-200': modelValue != item.value,
              }"
            >
              <a href="#" class="hover:text-white px-2 py-1" @click="switchTab(item.value)">
                {{ item.text }}
              </a>
            </div>
          </div>
        </div>
      </div>
    </div>
  </nav>
</template>

<script lang="ts">
import { defineComponent } from "vue";

export default defineComponent({
  name: "Header",
  data: function () {
    return {
      menu: [
        { value: "deck", text: "デッキ比較" },
        { value: "stats", text: "基礎ステータス" },
      ],
    };
  },
  props: {
    modelValue: {
      type: String,
      required: true,
    },
  },
  methods: {
    switchTab: function (active: string) {
      this.$emit("update:modelValue", active);
    },
  },
});
</script>

<style scoped>
.menu-item::after {
  content: "";
  position: absolute;
  left: 0;
  bottom: 0;
  width: 100%;
  display: block;
  border-bottom-width: 4px;
  border-color: rgb(252, 211, 77);
  opacity: 0;
  transition-property: opacity;
  transition-timing-function: cubic-bezier(0.4, 0, 0.2, 1);
  transition-duration: 250ms;
}

.menu-item.active-item::after {
  opacity: 1;
}
</style>
