<template>
  <!-- Grid -->
  <div class="grid grid-cols-3">
    <!-- Left -->
    <div class="p-4 overflow-y-auto" style="height: calc(100vh - 56px)">
      <div v-if="selectedId !== -1">
        <div class="flex justify-center">
          <support-card
            :id="selectedId"
            :rarity="selectedCard.rarity"
            :type="selectedCard.command_id"
            :diamond="+diamond"
            :level="level"
            :width="200"
            :class="animationClass"
          />
        </div>
        <div class="my-2">
          カード名: [{{ selectedCard.unique_name }}]
          {{ selectedCard.chara_name }}
        </div>
        <div class="flex items-center my-2">
          上限解放:
          <input class="mx-2 w-36" type="range" min="0" max="4" v-model="diamond" />
          {{ ["無", "1", "2", "3", "完"][+diamond] }}凸
        </div>
        <div class="my-2">
          <div
            v-if="selectedCard.unique != null"
            class="w-64 my-1 px-3 py-1 rounded-lg shadow-md border border-gray-300 font-bold"
            :class="{
              'bg-gray-400': level < selectedCard.unique.lv,
              'text-white': level < selectedCard.unique.lv,
            }"
            :style="{ color: level < selectedCard.unique.lv ? '#fff' : '#794016' }"
          >
            <div v-if="level < selectedCard.unique.lv">Lv{{ selectedCard.unique.lv }} で解放</div>
            {{ selectedCard.unique_name }}
            <div v-if="level >= selectedCard.unique.lv" class="pl-4">
              {{ effectText[selectedCard.unique.effect[0].type] }}
              {{ selectedCard.unique.effect[0].value
              }}{{ ["", "%"][+effectPer.includes(selectedCard.unique.effect[0].type)] }}
            </div>
            <div v-if="level >= selectedCard.unique.lv" class="pl-4">
              {{ effectText[selectedCard.unique.effect[1].type] }}
              {{ selectedCard.unique.effect[1].value
              }}{{ ["", "%"][+effectPer.includes(selectedCard.unique.effect[1].type)] }}
            </div>
          </div>
          <div
            v-for="effect in supportCardEffects"
            :key="effect.type"
            class="w-64 my-1 px-3 py-1 rounded-lg shadow-md border border-gray-300 font-bold"
            :class="{
              'bg-gray-400': effect.value === -1,
              'text-white': effect.value === -1,
            }"
            :style="{ color: effect.value === -1 ? '#fff' : '#794016' }"
          >
            <div v-if="effect.value === -1">Lv{{ effect.lv }} で解放</div>
            {{ effectText[effect.type] }}
            <span v-if="effect.value !== -1">
              {{ effect.value }}{{ effectPer.includes(effect.type) ? "%" : "" }}
            </span>
          </div>
        </div>
      </div>
    </div>

    <!-- Right -->
    <div class="col-span-2">
      <div class="p-4 h-32">
        <!-- Rarity -->
        <div class="grid grid-cols-9 my-2 max-w-5xl">
          <div class="col-span-2">レアリティ</div>
          <div
            v-for="item in [
              { value: 0, text: 'R' },
              { value: 1, text: 'SR' },
              { value: 2, text: 'SSR' },
            ]"
            :key="item.value"
          >
            <label class="cursor-pointer">
              <input
                type="checkbox"
                class="cursor-pointer rounded shadow-sm transition mx-1"
                :value="item.value"
                v-model="filterRarity"
              />
              {{ item.text }}
            </label>
          </div>
        </div>

        <!-- Command -->
        <div class="grid grid-cols-9 my-2 max-w-5xl">
          <div class="col-span-2">得意練習</div>
          <div
            v-for="item in [
              { value: 0, text: 'スピード' },
              { value: 1, text: 'スタミナ' },
              { value: 2, text: 'パワー' },
              { value: 3, text: '根性' },
              { value: 4, text: '賢さ' },
              { value: 5, text: '友人' },
            ]"
            :key="item.value"
          >
            <label class="cursor-pointer">
              <input
                type="checkbox"
                class="cursor-pointer rounded shadow-sm transition mx-1"
                :value="item.value"
                v-model="filterCommand"
              />
              {{ item.text }}
            </label>
          </div>
        </div>

        <!-- Reset button -->
        <div class="my-3">
          <button
            class="hover:bg-gray-100 border border-gray-600 rounded-xl shadow px-4 py-1 text-sm"
            @click="resetFilter"
          >
            絞り込みをリセット
          </button>
        </div>
      </div>

      <!-- Cards -->
      <div class="p-2 leading-none overflow-y-scroll" style="height: calc(100vh - 56px - 128px)">
        <support-card
          v-for="card in supportCardsFiltered"
          :id="card.id"
          :key="`support-card-${card.id}`"
          class="m-1"
          :rarity="card.rarity"
          :type="card.command_id"
          :width="120"
          @click="onClick(card.id)"
        />
      </div>
    </div>
  </div>
</template>

<script lang="ts">
import { defineComponent } from "vue";
import SupportCard from "./SupportCard.vue";
import SupportCardJson from "@/assets/support_card_data.json";

const effectText = [
  "",
  "友情ボーナス",
  "やる気効果アップ",
  "スピードボーナス",
  "スタミナボーナス",
  "パワーボーナス",
  "根性ボーナス",
  "賢さボーナス",
  "トレーニング効果アップ",
  "初期スピードアップ",
  "初期スタミナアップ",
  "初期パワーアップ",
  "初期根性アップ",
  "初期賢さアップ",
  "初期絆ゲージアップ",
  "レースボーナス",
  "ファン数ボーナス",
  "ヒントLvアップ",
  "ヒント発生率アップ",
  "得意率アップ",
  "",
  "",
  "",
  "",
  "",
  "イベント回復量アップ",
  "イベント効果アップ",
  "失敗率ダウン",
  "体力消費ダウン",
  "",
  "スキルPtボーナス",
  "賢さ友情回復量アップ",
];

const effectPer = [1, 2, 8, 15, 16, 18, 25, 26, 27, 28];

const trainingEffect = {
  speed: [
    { speed: 10, stamina: 0, power: 5, guts: 0, wiz: 0, skill: 2, vital: -21 },
    { speed: 11, stamina: 0, power: 5, guts: 0, wiz: 0, skill: 2, vital: -22 },
    { speed: 12, stamina: 0, power: 5, guts: 0, wiz: 0, skill: 2, vital: -23 },
    { speed: 13, stamina: 0, power: 6, guts: 0, wiz: 0, skill: 2, vital: -25 },
    { speed: 14, stamina: 0, power: 7, guts: 0, wiz: 0, skill: 2, vital: -27 },
  ],
  stamina: [
    { speed: 0, stamina: 9, power: 0, guts: 4, wiz: 0, skill: 2, vital: -19 },
    { speed: 0, stamina: 10, power: 0, guts: 4, wiz: 0, skill: 2, vital: -20 },
    { speed: 0, stamina: 11, power: 0, guts: 4, wiz: 0, skill: 2, vital: -21 },
    { speed: 0, stamina: 12, power: 0, guts: 5, wiz: 0, skill: 2, vital: -23 },
    { speed: 0, stamina: 13, power: 0, guts: 6, wiz: 0, skill: 2, vital: -25 },
  ],
  power: [
    { speed: 0, stamina: 5, power: 8, guts: 0, wiz: 0, skill: 2, vital: -20 },
    { speed: 0, stamina: 5, power: 9, guts: 0, wiz: 0, skill: 2, vital: -21 },
    { speed: 0, stamina: 5, power: 10, guts: 0, wiz: 0, skill: 2, vital: -22 },
    { speed: 0, stamina: 6, power: 11, guts: 0, wiz: 0, skill: 2, vital: -24 },
    { speed: 0, stamina: 7, power: 12, guts: 0, wiz: 0, skill: 2, vital: -26 },
  ],
  guts: [
    { speed: 4, stamina: 0, power: 4, guts: 8, wiz: 0, skill: 2, vital: -22 },
    { speed: 4, stamina: 0, power: 4, guts: 9, wiz: 0, skill: 2, vital: -23 },
    { speed: 4, stamina: 0, power: 4, guts: 10, wiz: 0, skill: 2, vital: -24 },
    { speed: 5, stamina: 0, power: 4, guts: 11, wiz: 0, skill: 2, vital: -26 },
    { speed: 5, stamina: 0, power: 5, guts: 12, wiz: 0, skill: 2, vital: -28 },
  ],
  wiz: [
    { speed: 2, stamina: 0, power: 0, guts: 0, wiz: 9, skill: 4, vital: 5 },
    { speed: 2, stamina: 0, power: 0, guts: 0, wiz: 10, skill: 4, vital: 5 },
    { speed: 2, stamina: 0, power: 0, guts: 0, wiz: 11, skill: 4, vital: 5 },
    { speed: 3, stamina: 0, power: 0, guts: 0, wiz: 12, skill: 4, vital: 5 },
    { speed: 4, stamina: 0, power: 0, guts: 0, wiz: 13, skill: 4, vital: 5 },
  ],
};

const motivation = [
  { label: "絶好調", value: 0.2 },
  { label: "好調", value: 0.1 },
  { label: "普通", value: 0 },
  { label: "不調", value: -0.1 },
  { label: "絶不調", value: -0.2 },
];

export default defineComponent({
  name: "App",
  components: { SupportCard },

  data: function () {
    const supportCards = Object.fromEntries(SupportCardJson.map((card) => [card.id, card]));
    const emptyNumberArray: number[] = [];

    return {
      supportCards,
      effectText,
      effectPer,
      motivation,
      selectedId: -1,
      diamond: "4",
      trainingLv: 5,
      motivationValue: 0.2,
      filterRarity: [...emptyNumberArray],
      filterCommand: [...emptyNumberArray],
      activeTab: "stats",
      animationClass: "",
    };
  },

  computed: {
    selectedCard: function (): typeof SupportCardJson[number] {
      return this.supportCards[this.selectedId];
    },

    supportCardsSorted: function (): typeof SupportCardJson {
      let cards = SupportCardJson;
      cards.sort((lhs, rhs) => {
        return (
          (rhs.rarity - lhs.rarity) * 1000000000 +
          (lhs.chara_id - rhs.chara_id) * 100000 +
          (lhs.id - rhs.id)
        );
      });
      return cards;
    },

    supportCardsFiltered: function (): typeof SupportCardJson {
      let cards = this.supportCardsSorted;
      if (this.filterRarity.length) {
        cards = cards.filter((card) => this.filterRarity.includes(card.rarity));
      }
      if (this.filterCommand.length) {
        cards = cards.filter((card) => this.filterCommand.includes(card.command_id));
      }
      return cards;
    },

    level: function (): number {
      return 20 + 5 * +this.diamond + 5 * this.selectedCard.rarity;
    },

    supportCardEffects: function (): { type: number; value: number; lv: number }[] {
      let effects: { type: number; value: number; lv: number }[] = [];

      for (const effect of this.selectedCard.effect) {
        let lo = { lv: -1, value: -1 };
        let hi = { lv: -1, value: -1 };

        for (let i = Math.floor(this.level / 5); i >= 0; --i) {
          if (effect.value[i] !== -1) {
            lo = { lv: i * 5 + +(i === 0), value: effect.value[i] };
            break;
          }
        }

        for (let i = Math.ceil(this.level / 5); i <= 10; ++i) {
          if (effect.value[i] !== -1) {
            hi = { lv: i * 5, value: effect.value[i] };
            break;
          }
        }

        if (lo.value === -1) {
          effects.push({ type: effect.type, value: -1, lv: hi.lv });
        } else if (hi.value === -1 || lo.lv === hi.lv) {
          effects.push({ type: effect.type, value: lo.value, lv: -1 });
        } else {
          const value = lo.value + ((this.level - lo.lv) * (hi.value - lo.value)) / (hi.lv - lo.lv);
          effects.push({ type: effect.type, value: Math.floor(value), lv: -1 });
        }
      }

      effects.sort(function (lhs, rhs) {
        if (lhs.value === -1 && rhs.value === -1) {
          return (lhs.lv - rhs.lv) * 100 + (lhs.type - rhs.type);
        } else if (lhs.value === -1) {
          return 1;
        } else if (rhs.value === -1) {
          return -1;
        } else {
          return lhs.type - rhs.type;
        }
      });

      return effects;
    },

    trainingEffect: function (): {
      text: string;
      effect: typeof trainingEffect[keyof typeof trainingEffect][number];
    } {
      type KeyType = keyof typeof trainingEffect[keyof typeof trainingEffect][number];
      const keys: KeyType[] = ["speed", "stamina", "power", "guts", "wiz"];
      const key = keys[this.selectedCard.command_id];
      const effect = { ...trainingEffect[key as keyof typeof trainingEffect][this.trainingLv - 1] };
      const text = ["スピード", "スタミナ", "パワー", "根性", "賢さ"][this.selectedCard.command_id];

      // 基礎ボーナス (固有)
      if (this.selectedCard.unique != null && this.level >= this.selectedCard.unique.lv) {
        for (const supportEffect of this.selectedCard.unique.effect) {
          if (3 <= supportEffect.type && supportEffect.type <= 7) {
            const key = keys[supportEffect.type - 3];
            if (effect[key] !== 0) {
              effect[key] += supportEffect.value;
            }
          }
        }
      }

      // 基礎ボーナス
      for (const supportEffect of this.supportCardEffects) {
        if (3 <= supportEffect.type && supportEffect.type <= 7 && supportEffect.value !== -1) {
          const key = keys[supportEffect.type - 3];
          if (effect[key] !== 0) {
            effect[key] += supportEffect.value;
          }
        }
      }

      // 友情ボーナス (固有)
      if (this.selectedCard.unique != null && this.level >= this.selectedCard.unique.lv) {
        for (const supportEffect of this.selectedCard.unique.effect) {
          if (supportEffect.type === 1) {
            for (let i = 0; i < 5; ++i) {
              effect[keys[i]] *= 1.0 + supportEffect.value / 100;
            }
          }
        }
      }

      // 友情ボーナス
      for (const supportEffect of this.supportCardEffects) {
        if (supportEffect.type === 1 && supportEffect.value !== -1) {
          for (let i = 0; i < 5; ++i) {
            effect[keys[i]] *= 1.0 + supportEffect.value / 100;
          }
        }
      }

      let motivationCoef = 1.0;

      // やる気効果 (固有)
      if (this.selectedCard.unique != null && this.level >= this.selectedCard.unique.lv) {
        for (const supportEffect of this.selectedCard.unique.effect) {
          if (supportEffect.type === 2) {
            motivationCoef += supportEffect.value / 100;
          }
        }
      }

      // やる気効果
      for (const supportEffect of this.supportCardEffects) {
        if (supportEffect.type === 2 && supportEffect.value !== -1) {
          motivationCoef += supportEffect.value / 100;
        }
      }

      for (let i = 0; i < 5; ++i) {
        effect[keys[i]] *= 1.0 + this.motivationValue * motivationCoef;
      }

      let trainingCoef = 1.0;

      // トレーニング効果 (固有)
      if (this.selectedCard.unique != null && this.level >= this.selectedCard.unique.lv) {
        for (const supportEffect of this.selectedCard.unique.effect) {
          if (supportEffect.type === 8) {
            trainingCoef += supportEffect.value / 100;
          }
        }
      }

      // トレーニング効果
      for (const supportEffect of this.supportCardEffects) {
        if (supportEffect.type === 8 && supportEffect.value !== -1) {
          trainingCoef += supportEffect.value / 100;
        }
      }

      for (let i = 0; i < 5; ++i) {
        effect[keys[i]] *= trainingCoef;
      }

      // 人数補正
      for (let i = 0; i < 5; ++i) {
        effect[keys[i]] *= 1.05;
      }

      // 切り捨て
      for (let i = 0; i < 5; ++i) {
        effect[keys[i]] = Math.floor(effect[keys[i]]);
      }

      return { text, effect };
    },

    trainingRate: function (): number {
      let rate = 100;

      if (this.selectedCard.unique != null && this.level >= this.selectedCard.unique.lv) {
        for (const supportEffect of this.selectedCard.unique.effect) {
          if (supportEffect.type === 19) {
            rate *= 1.0 + supportEffect.value / 100;
          }
        }
      }

      for (const supportEffect of this.supportCardEffects) {
        if (supportEffect.type === 19 && supportEffect.value !== -1) {
          rate *= 1.0 + supportEffect.value / 100;
        }
      }

      return rate / (rate + 450);
    },
  },

  methods: {
    onClick: function (id: number) {
      if (this.selectedId != id) {
        this.selectedId = id;
        this.animationClass = "selected";
        setTimeout(() => (this.animationClass = "select-animation"), 10);
      }
    },

    changeDiamond: function (curValue: number, oldValue: number) {
      const oldMax = 20 + 5 * this.supportCards[this.selectedId].rarity + 5 * oldValue;
      const curMax = 20 + 5 * this.supportCards[this.selectedId].rarity + 5 * curValue;
      if (curValue > oldValue) {
        if (this.level == oldMax) {
          this.level = curMax;
        }
      } else if (curValue < oldValue) {
        this.level = Math.min(this.level, curMax);
      }
    },

    resetFilter: function () {
      this.filterRarity = [];
      this.filterCommand = [];
    },
  },
});
</script>

<style scoped>
.selected {
  transform: rotateY(90deg);
}

.select-animation {
  animation: bounce-in 0.25s;
}

@keyframes bounce-in {
  0% {
    transform: rotateY(90deg);
  }
  100% {
    transform: rotateY(0deg);
  }
}
</style>
